--[[\n    Advanced UI Layout - Full featured UI matching the reference design\n]]\n\nlocal UILibrary = loadstring(game:HttpGet(\"https://raw.githubusercontent.com/dudu69doglei93829327jb095n4b3n/ui-library/main/src/init.lua\"))()\n\n-- Create main screen\nlocal screen = UILibrary.Screen.new()\nscreen.frame.BackgroundColor3 = Color3.fromRGB(20, 20, 20)\nscreen.frame.BackgroundTransparency = 0\n\n-- === LEFT SIDEBAR ===\nlocal sidebar = UILibrary.Panel.new({\n    parent = screen.frame,\n    position = UDim2.new(0, 0, 0, 0),\n    size = UDim2.new(0, 150, 1, 0),\n    backgroundColor = Color3.fromRGB(30, 30, 30)\n})\nsidebar.frame.BackgroundTransparency = 0\n\n-- Logo\nlocal logo = UILibrary.Label.new({\n    parent = sidebar.frame,\n    text = \"⬡\",\n    position = UDim2.new(0.5, -20, 0, 15),\n    size = UDim2.new(0, 40, 0, 40),\n    textSize = 32,\n    textColor = Color3.fromRGB(0, 150, 255),\n    backgroundTransparency = 1\n})\n\nlocal logoText = UILibrary.Label.new({\n    parent = sidebar.frame,\n    text = \"polygon\",\n    position = UDim2.new(0, 5, 0, 60),\n    size = UDim2.new(1, -10, 0, 20),\n    textSize = 12,\n    textColor = Color3.fromRGB(200, 200, 200),\n    backgroundTransparency = 1\n})\n\n-- Menu Items\nlocal menuItems = {\"aim\", \"visuals\", \"misc\", \"config\", \"lua\"}\nfor i, item in ipairs(menuItems) do\n    local isActive = (item == \"aim\")\n    UILibrary.Label.new({\n        parent = sidebar.frame,\n        text = item,\n        position = UDim2.new(0, 10, 0, 90 + (i - 1) * 25),\n        size = UDim2.new(1, -20, 0, 20),\n        textSize = 12,\n        textColor = isActive and Color3.fromRGB(0, 150, 255) or Color3.fromRGB(120, 120, 120),\n        backgroundTransparency = 1\n    })\nend\n\n-- === MAIN CONTENT AREA ===\nlocal mainContent = UILibrary.Panel.new({\n    parent = screen.frame,\n    position = UDim2.new(0, 150, 0, 0),\n    size = UDim2.new(1, -150, 1, 0),\n    backgroundColor = Color3.fromRGB(20, 20, 20)\n})\nmainContent.frame.BackgroundTransparency = 0\n\n-- === TOP TAB NAVIGATION ===\nlocal tabBar = UILibrary.Panel.new({\n    parent = mainContent.frame,\n    position = UDim2.new(0, 0, 0, 0),\n    size = UDim2.new(1, 0, 0, 40),\n    backgroundColor = Color3.fromRGB(15, 15, 15)\n})\ntabBar.frame.BackgroundTransparency = 0\n\nlocal tabs = {\"players\", \"world\", \"items\", \"stash\"}\nfor i, tab in ipairs(tabs) do\n    local isActive = (tab == \"players\")\n    UILibrary.Label.new({\n        parent = tabBar.frame,\n        text = tab,\n        position = UDim2.new(0, 25 + (i - 1) * 110, 0, 12),\n        size = UDim2.new(0, 100, 0, 20),\n        textSize = 12,\n        textColor = isActive and Color3.fromRGB(0, 150, 255) or Color3.fromRGB(120, 120, 120),\n        backgroundTransparency = 1\n    })\nend\n\n-- === LEFT PANEL (TARGET & OPTIONS) ===\nlocal leftContentPanel = UILibrary.Panel.new({\n    parent = mainContent.frame,\n    position = UDim2.new(0, 20, 0, 55),\n    size = UDim2.new(0, 290, 1, -75),\n    backgroundColor = Color3.fromRGB(25, 25, 25)\n})\nleftContentPanel.frame.BackgroundTransparency = 0\n\n-- Target section title\nUILibrary.Label.new({\n    parent = leftContentPanel.frame,\n    text = \"Target\",\n    position = UDim2.new(0, 10, 0, 10),\n    size = UDim2.new(1, -20, 0, 20),\n    textSize = 13,\n    textColor = Color3.fromRGB(200, 200, 200),\n    backgroundTransparency = 1\n})\n\n-- Target icons placeholder\nUILibrary.Label.new({\n    parent = leftContentPanel.frame,\n    text = \"👤  👥  👨\",\n    position = UDim2.new(0, 10, 0, 35),\n    size = UDim2.new(1, -20, 0, 30),\n    textSize = 24,\n    textColor = Color3.fromRGB(150, 150, 150),\n    backgroundTransparency = 1\n})\n\n-- Options section\nUILibrary.Label.new({\n    parent = leftContentPanel.frame,\n    text = \"Options\",\n    position = UDim2.new(0, 10, 0, 75),\n    size = UDim2.new(1, -20, 0, 20),\n    textSize = 13,\n    textColor = Color3.fromRGB(200, 200, 200),\n    backgroundTransparency = 1\n})\n\n-- Checkboxes with range display\nlocal options = {\n    {text = \"Enemy ESP\", checked = true},\n    {text = \"Maximum Range\", checked = true, range = \"400m\"},\n    {text = \"Name\", checked = true},\n    {text = \"Box\", checked = true},\n    {text = \"Skeleton\", checked = true},\n    {text = \"Flags\", checked = true}\n}\n\nfor i, opt in ipairs(options) do\n    local checkbox = UILibrary.Checkbox.new({\n        parent = leftContentPanel.frame,\n        text = opt.text,\n        position = UDim2.new(0, 10, 0, 95 + (i - 1) * 28),\n        size = UDim2.new(0.6, -15, 0, 25),\n        checked = opt.checked\n    })\n    checkbox.box.BackgroundColor3 = Color3.fromRGB(0, 120, 215)\n    checkbox.box.TextColor3 = Color3.fromRGB(255, 255, 255)\n    checkbox.label.TextColor3 = Color3.fromRGB(200, 200, 200)\n    \n    -- Range display for specific options\n    if opt.range then\n        UILibrary.Label.new({\n            parent = leftContentPanel.frame,\n            text = opt.range,\n            position = UDim2.new(0.6, 5, 0, 95 + (i - 1) * 28),\n            size = UDim2.new(0.4, -15, 0, 25),\n            textSize = 11,\n            textColor = Color3.fromRGB(150, 150, 150),\n            backgroundTransparency = 1\n        })\n    end\nend\n\n-- Additional options with color indicators\nlocal additionalOptions = {\n    {text = \"Networth, Distance, Weapon, K/D...\"},\n    {text = \"Health\"},\n    {text = \"Snapline\"},\n    {text = \"Head circle\"},\n    {text = \"Chams\"}\n}\n\nlocal optionYOffset = 95 + #options * 28\nfor i, opt in ipairs(additionalOptions) do\n    UILibrary.Label.new({\n        parent = leftContentPanel.frame,\n        text = opt.text,\n        position = UDim2.new(0, 25, 0, optionYOffset + (i - 1) * 22),\n        size = UDim2.new(1, -35, 0, 20),\n        textSize = 11,\n        textColor = Color3.fromRGB(150, 150, 150),\n        backgroundTransparency = 1\n    })\nend\n\n-- === RIGHT PANEL (PREVIEW) ===\nlocal rightContentPanel = UILibrary.Panel.new({\n    parent = mainContent.frame,\n    position = UDim2.new(0, 320, 0, 55),\n    size = UDim2.new(1, -340, 1, -75),\n    backgroundColor = Color3.fromRGB(25, 25, 25)\n})\nrightContentPanel.frame.BackgroundTransparency = 0\n\n-- Preview title\nUILibrary.Label.new({\n    parent = rightContentPanel.frame,\n    text = \"Preview\",\n    position = UDim2.new(0, 10, 0, 10),\n    size = UDim2.new(1, -20, 0, 20),\n    textSize = 13,\n    textColor = Color3.fromRGB(200, 200, 200),\n    backgroundTransparency = 1\n})\n\n-- Preview viewport (black area)\nlocal preview = UILibrary.Panel.new({\n    parent = rightContentPanel.frame,\n    position = UDim2.new(0, 10, 0, 40),\n    size = UDim2.new(1, -20, 1, -60),\n    backgroundColor = Color3.fromRGB(15, 15, 15)\n})\npreview.frame.BackgroundTransparency = 0\n\n-- Preview content with border\nlocal previewInner = UILibrary.Panel.new({\n    parent = preview.frame,\n    position = UDim2.new(0, 5, 0, 5),\n    size = UDim2.new(1, -10, 1, -10),\n    backgroundColor = Color3.fromRGB(15, 15, 15)\n})\npreviewInner.frame.BackgroundTransparency = 0\n\n-- ESP preview text\nUILibrary.Label.new({\n    parent = previewInner.frame,\n    text = \"OPponent\\n1000\\nHP\\nESP K/D\\nUESC\",\n    position = UDim2.new(0, 10, 0, 10),\n    size = UDim2.new(1, -20, 1, -20),\n    textSize = 10,\n    textColor = Color3.fromRGB(0, 255, 100),\n    backgroundTransparency = 1\n})\n\n-- Status info at bottom\nUILibrary.Label.new({\n    parent = rightContentPanel.frame,\n    text = \"HTML\\nESPENE: 330/31\",\n    position = UDim2.new(0, 10, 1, -50),\n    size = UDim2.new(1, -20, 0, 40),\n    textSize = 9,\n    textColor = Color3.fromRGB(100, 100, 100),\n    backgroundTransparency = 1\n})\n\nprint(\"✅ Advanced UI Layout loaded successfully!\")\n